var e=[{id:`L2_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`좋아. 배짱 하나는 다시 봤어. 물론 내 옆에 세워 놔도 안 꿀리려면 갈 길이 멀지만. 그래도 안심해. 미래의 탑스타로서 내 열성팬 1호만은 제대로 코칭해 줄 테니까!`,JPN:`意外といい度胸してるのね。正直見直したわ。アタシと肩を並べるにはまだまだ先は長いけど……心配要らないわよ。ガチファン第1号の面倒くらい見てあげる。未来のトップスターであるこのアタシがみっちりコーチしてあげるわよ！`,ENG:`Yes, that's the spirit! Well, it'll be a while before you'll look good enough to stand next to me, but don't worry. I'll make sure you become a perfect match for the future top star, from head to toe!`,TWN:`很好！你的膽量讓我刮目相看了。當然，要站在我身旁不被比下去，你還差得遠呢。不過放心吧，身為未來的超級巨星，我會好好訓練我的頭號粉絲的！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`엑, 그건 싫어?`,JPN:`えっ、嫌なの？`,ENG:`Ack, you don't want that?`,TWN:`咦，你不要嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};